{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "action": "read",
        "resource": "license_utilization_report",
        "context": "Checking permission to read license and seat utilization data for analysis"
      },
      "depends_on": []
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "license_assignments",
        "filter": {
          "platform": "salesforce",
          "status": { "$in": ["active", "assigned", "unassigned", "inactive"] }
        },
        "projection": {
          "user_id": 1,
          "license_type": 1,
          "status": 1,
          "last_login_date": 1,
          "assigned_date": 1,
          "org_id": 1
        },
        "limit": 10000
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "license_contracts",
        "filter": {
          "platform": "salesforce",
          "contract_status": "active"
        },
        "projection": {
          "org_id": 1,
          "license_type": 1,
          "licensed_seats_total": 1,
          "contract_start_date": 1,
          "contract_end_date": 1,
          "annual_cost_per_seat": 1
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT u.user_id, u.license_type, u.org_id, u.assigned_date, u.is_active, MAX(al.activity_timestamp) AS last_active_date, COUNT(al.activity_id) AS activity_count_90d FROM salesforce_user_licenses u LEFT JOIN salesforce_activity_log al ON u.user_id = al.user_id AND al.activity_timestamp >= DATEADD('day', -90, CURRENT_TIMESTAMP()) GROUP BY u.user_id, u.license_type, u.org_id, u.assigned_date, u.is_active ORDER BY last_active_date ASC NULLS FIRST"
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT license_type, org_id, COUNT(*) AS total_assigned, SUM(CASE WHEN last_login_date >= DATEADD('day', -30, CURRENT_TIMESTAMP()) THEN 1 ELSE 0 END) AS active_last_30d, SUM(CASE WHEN last_login_date >= DATEADD('day', -90, CURRENT_TIMESTAMP()) THEN 1 ELSE 0 END) AS active_last_90d, SUM(CASE WHEN last_login_date < DATEADD('day', -90, CURRENT_TIMESTAMP()) OR last_login_date IS NULL THEN 1 ELSE 0 END) AS inactive
